void reverse_str(char *s) {
    int l = 0, r = 0;
    while (s[r]) r++;
    r--;
    while (l < r) {
        char tmp = s[l]; s[l++] = s[r]; s[r--] = tmp;
    }
}

void *my_memcpy(void *dst, const void *src, unsigned long n) {
    unsigned char *d = dst;
    const unsigned char *s = src;
    while (n--) *d++ = *s++;
    return dst;
}

